function matchZoteroItems(text) {
	const regex = /《(.*?)》/gm;
	const matches = text.match(regex);
	return matches ? matches.map(match => match.slice(1, -1)) : "";
}

function levenshteinDistance(a, b) {
	// Levenshtein距离计算相似度 by ChatGPT @2024-01-04 
	const m = a.length;
	const n = b.length;
	const dp = Array.from(Array(m + 1), () => Array(n + 1).fill(0));

	for (let i = 0; i <= m; i++) {
		dp[i][0] = i;
	}

	for (let j = 0; j <= n; j++) {
		dp[0][j] = j;
	}

	for (let i = 1; i <= m; i++) {
		for (let j = 1; j <= n; j++) {
			if (a[i - 1] === b[j - 1]) {
				dp[i][j] = dp[i - 1][j - 1];
			} else {
				dp[i][j] = Math.min(
					dp[i - 1][j] + 1, // 删除操作
					dp[i][j - 1] + 1, // 插入操作
					dp[i - 1][j - 1] + 1 // 替换操作
				);
			}
		}
	}

	return dp[m][n];
}
